import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import {
  AnalyticsService,
  resolveGranularity,
  previousPeriod,
  buildMetricSummary,
} from '../../src/services/analytics.service.js';
import type { MetricType, TimeGranularity } from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// resolveGranularity
// ---------------------------------------------------------------------------

describe('resolveGranularity', () => {
  it('should return explicit granularity when provided', () => {
    expect(resolveGranularity('2026-01-01', '2026-06-01', 'hour')).toBe('hour');
    expect(resolveGranularity('2026-01-01', '2026-06-01', 'day')).toBe('day');
    expect(resolveGranularity('2026-01-01', '2026-06-01', 'week')).toBe('week');
    expect(resolveGranularity('2026-01-01', '2026-06-01', 'month')).toBe('month');
  });

  it('should return "hour" for ranges <= 2 days', () => {
    expect(resolveGranularity('2026-01-01', '2026-01-02')).toBe('hour');
    expect(resolveGranularity('2026-01-01', '2026-01-03')).toBe('hour');
  });

  it('should return "day" for ranges <= 30 days', () => {
    expect(resolveGranularity('2026-01-01', '2026-01-10')).toBe('day');
    expect(resolveGranularity('2026-01-01', '2026-01-31')).toBe('day');
  });

  it('should return "week" for ranges <= 90 days', () => {
    expect(resolveGranularity('2026-01-01', '2026-03-01')).toBe('week');
    expect(resolveGranularity('2026-01-01', '2026-04-01')).toBe('week');
  });

  it('should return "month" for ranges > 90 days', () => {
    expect(resolveGranularity('2026-01-01', '2026-07-01')).toBe('month');
    expect(resolveGranularity('2025-01-01', '2026-01-01')).toBe('month');
  });

  it('should handle same-day range as <= 2 days', () => {
    expect(resolveGranularity('2026-01-01', '2026-01-01')).toBe('hour');
  });

  it('should handle ISO 8601 timestamps with time components', () => {
    expect(
      resolveGranularity('2026-01-01T00:00:00Z', '2026-01-01T12:00:00Z'),
    ).toBe('hour');
  });
});

// ---------------------------------------------------------------------------
// previousPeriod
// ---------------------------------------------------------------------------

describe('previousPeriod', () => {
  it('should compute a period of equal length ending at from', () => {
    const result = previousPeriod({
      from: '2026-01-11T00:00:00.000Z',
      to: '2026-01-21T00:00:00.000Z',
    });

    expect(result.to).toBe('2026-01-11T00:00:00.000Z');
    // 10-day range → previous period starts 10 days before from
    expect(result.from).toBe('2026-01-01T00:00:00.000Z');
  });

  it('should handle a 1-day range', () => {
    const result = previousPeriod({
      from: '2026-03-02T00:00:00.000Z',
      to: '2026-03-03T00:00:00.000Z',
    });

    expect(result.from).toBe('2026-03-01T00:00:00.000Z');
    expect(result.to).toBe('2026-03-02T00:00:00.000Z');
  });

  it('should handle a zero-length range (from === to)', () => {
    const result = previousPeriod({
      from: '2026-01-15T00:00:00.000Z',
      to: '2026-01-15T00:00:00.000Z',
    });

    expect(result.from).toBe('2026-01-15T00:00:00.000Z');
    expect(result.to).toBe('2026-01-15T00:00:00.000Z');
  });

  it('should handle long ranges', () => {
    const result = previousPeriod({
      from: '2026-07-01T00:00:00.000Z',
      to: '2026-12-31T00:00:00.000Z',
    });

    // The previous period "to" should equal the original "from"
    expect(result.to).toBe('2026-07-01T00:00:00.000Z');
    // Duration should be equal
    const originalDuration =
      new Date('2026-12-31T00:00:00.000Z').getTime() -
      new Date('2026-07-01T00:00:00.000Z').getTime();
    const prevDuration =
      new Date(result.to).getTime() - new Date(result.from).getTime();
    expect(prevDuration).toBe(originalDuration);
  });
});

// ---------------------------------------------------------------------------
// buildMetricSummary
// ---------------------------------------------------------------------------

describe('buildMetricSummary', () => {
  it('should compute positive change and "up" trend', () => {
    const summary = buildMetricSummary('revenue', 'Revenue', 150, 100);

    expect(summary.name).toBe('revenue');
    expect(summary.label).toBe('Revenue');
    expect(summary.value).toBe(150);
    expect(summary.previousValue).toBe(100);
    expect(summary.changePercent).toBe(50);
    expect(summary.trend).toBe('up');
  });

  it('should compute negative change and "down" trend', () => {
    const summary = buildMetricSummary('orders', 'Orders', 80, 100);

    expect(summary.changePercent).toBe(-20);
    expect(summary.trend).toBe('down');
  });

  it('should return "flat" trend for small changes (within ±0.5%)', () => {
    const summary = buildMetricSummary('orders', 'Orders', 100, 100);

    expect(summary.changePercent).toBe(0);
    expect(summary.trend).toBe('flat');
  });

  it('should treat exactly 0.5% as flat', () => {
    // 0.5% of 200 = 1, so value=201 gives exactly 0.5%
    const summary = buildMetricSummary('orders', 'Orders', 201, 200);

    expect(summary.changePercent).toBe(0.5);
    expect(summary.trend).toBe('flat');
  });

  it('should treat exactly -0.5% as flat', () => {
    // -0.5% of 200 = -1, so value=199 gives exactly -0.5%
    const summary = buildMetricSummary('orders', 'Orders', 199, 200);

    expect(summary.changePercent).toBe(-0.5);
    expect(summary.trend).toBe('flat');
  });

  it('should handle previousValue of 0 with positive value → 100%', () => {
    const summary = buildMetricSummary('users', 'Users', 50, 0);

    expect(summary.changePercent).toBe(100);
    expect(summary.trend).toBe('up');
  });

  it('should handle both values being 0 → 0% flat', () => {
    const summary = buildMetricSummary('users', 'Users', 0, 0);

    expect(summary.changePercent).toBe(0);
    expect(summary.trend).toBe('flat');
  });

  it('should handle large numbers', () => {
    const summary = buildMetricSummary('revenue', 'Revenue', 1_000_000, 500_000);

    expect(summary.changePercent).toBe(100);
    expect(summary.trend).toBe('up');
  });

  it('should handle fractional values', () => {
    const summary = buildMetricSummary('avg', 'Avg', 10.5, 10);

    expect(summary.changePercent).toBe(5);
    expect(summary.trend).toBe('up');
  });
});

// ---------------------------------------------------------------------------
// AnalyticsService
// ---------------------------------------------------------------------------

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('getDashboard', () => {
    it('should return a valid DashboardData shape', () => {
      const result = service.getDashboard({
        from: '2026-01-01',
        to: '2026-01-31',
      });

      expect(result.dateRange).toEqual({ from: '2026-01-01', to: '2026-01-31' });
      expect(result.kpis).toBeDefined();
      expect(result.kpis.totalOrders).toBeDefined();
      expect(result.kpis.totalRevenue).toBeDefined();
      expect(result.kpis.averageOrderValue).toBeDefined();
      expect(result.kpis.totalUsers).toBeDefined();
      expect(Array.isArray(result.orderTimeSeries)).toBe(true);
      expect(Array.isArray(result.revenueTimeSeries)).toBe(true);
      expect(Array.isArray(result.ordersByStatus)).toBe(true);
      expect(Array.isArray(result.topProducts)).toBe(true);
    });

    it('should have properly structured KPI metric summaries', () => {
      const result = service.getDashboard({
        from: '2026-01-01',
        to: '2026-01-31',
      });

      for (const kpi of Object.values(result.kpis)) {
        expect(kpi).toHaveProperty('name');
        expect(kpi).toHaveProperty('label');
        expect(kpi).toHaveProperty('value');
        expect(kpi).toHaveProperty('previousValue');
        expect(kpi).toHaveProperty('changePercent');
        expect(kpi).toHaveProperty('trend');
        expect(['up', 'down', 'flat']).toContain(kpi.trend);
      }
    });

    it('should set the correct dateRange from the query', () => {
      const result = service.getDashboard({
        from: '2026-03-01',
        to: '2026-03-15',
      });

      expect(result.dateRange.from).toBe('2026-03-01');
      expect(result.dateRange.to).toBe('2026-03-15');
    });

    it('should accept an explicit granularity without error', () => {
      const result = service.getDashboard({
        from: '2026-01-01',
        to: '2026-12-31',
        granularity: 'week',
      });

      expect(result).toBeDefined();
      expect(result.dateRange).toBeDefined();
    });

    it('should work with a single-day range', () => {
      const result = service.getDashboard({
        from: '2026-06-15',
        to: '2026-06-15',
      });

      expect(result.dateRange.from).toBe('2026-06-15');
      expect(result.dateRange.to).toBe('2026-06-15');
    });
  });

  describe('getMetricTimeSeries', () => {
    const metricTypes: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];

    it('should return a valid MetricTimeSeriesResponse shape', () => {
      const result = service.getMetricTimeSeries('orders', {
        from: '2026-01-01',
        to: '2026-01-31',
      });

      expect(result.metric).toBe('orders');
      expect(result.dateRange).toEqual({ from: '2026-01-01', to: '2026-01-31' });
      expect(result.granularity).toBeDefined();
      expect(result.summary).toBeDefined();
      expect(Array.isArray(result.series)).toBe(true);
    });

    it.each(metricTypes)('should accept metric type "%s"', (type) => {
      const result = service.getMetricTimeSeries(type, {
        from: '2026-01-01',
        to: '2026-01-31',
      });

      expect(result.metric).toBe(type);
    });

    it('should resolve granularity automatically based on date range', () => {
      // <= 2 days → hour
      const hourResult = service.getMetricTimeSeries('orders', {
        from: '2026-01-01',
        to: '2026-01-02',
      });
      expect(hourResult.granularity).toBe('hour');

      // <= 30 days → day
      const dayResult = service.getMetricTimeSeries('orders', {
        from: '2026-01-01',
