      });
      expect(weekResult.granularity).toBe('week');

      // > 90 days → month
      const monthResult = service.getMetricTimeSeries('orders', {
        from: '2026-01-01',
        to: '2026-12-31',
      });
      expect(monthResult.granularity).toBe('month');
